/*==============================================================================
 * Type Definitions
 *============================================================================*/

/**
 * @brief Flight control output structure.
 *
 * @details
 * This structure contains the attitude controller outputs
 * generated by the flight control algorithm.
 *
 * These outputs are typically mixed into motor commands
 * by the motor mixer module.
 */
typedef struct
{
    float roll_out;     // Roll axis control output
    float pitch_out;    // Pitch axis control output
    float yaw_out;      // Yaw axis control output
} ControlOutput_t;

